(5806, 300, '_about_accordion_sec_acc_repeater_1_titletab', 'field_69fc8103aea53'),
(5807, 300, 'about_accordion_sec_acc_repeater_1_contenttab', '   <p> <strong>This is the third item\'s accordion body.</strong> It is hidden by\r\n                                            default, until the collapse plugin adds the appropriate classes that we use\r\n                                            to\r\n                                            style each element. These classes control the overall appearance, as well as\r\n                                            the\r\n                                            showing and hiding via CSS transitions. You can modify any of this with\r\n                                            custom\r\n                                            CSS or overriding our default variables. It\'s also worth noting that just\r\n                                            about\r\n                                            any HTML can go within the <code>.accordion-body</code>, though the\r\n                                            transition\r\n                                            does limit overflow.</p>'),
(5808, 300, '_about_accordion_sec_acc_repeater_1_contenttab', 'field_69fc8113aea54'),
(5809, 300, 'about_accordion_sec_acc_repeater_2_titletab', '  Our mission'),
(5810, 300, '_about_accordion_sec_acc_repeater_2_titletab', 'field_69fc8103aea53'),
(5811, 300, 'about_accordion_sec_acc_repeater_2_contenttab', '   <p> <strong>This is the third item\'s accordion body.</strong> It is hidden by\r\n                                            default, until the collapse plugin adds the appropriate classes that we use\r\n                                            to\r\n                                            style each element. These classes control the overall appearance, as well as\r\n                                            the\r\n                                            showing and hiding via CSS transitions. You can modify any of this with\r\n                                            custom\r\n                                            CSS or overriding our default variables. It\'s also worth noting that just\r\n                                            about\r\n                                            any HTML can go within the <code>.accordion-body</code>, though the\r\n                                            transition\r\n                                            does limit overflow.</p>'),
